// NQxb_Gateway_v1__Normalize_Request (Phase 1 - Bearer Auth Support)
// Canonicalize inbound request + extract auth context.
//
// Output contract (stable):
//   $json.gw_action, $json.gw_workspace_id, $json.artifact_type, $json.artifact_id, $json.selector
// Plus "request echoes" that survive later DB row replacement:
//   $json.req_artifact_type, $json.req_artifact_id
// Auth context (new in Phase 1):
//   $json._auth_method ('bearer' | 'basic' | 'none')
//   $json._bearer_token (if bearer)
//   $json._basic_credentials (if basic)
//   $json._client_owner_user_id (legacy pass-through)
// Non-contract debug:
//   $json._gw_debug

const raw = $json ?? {};

// n8n Webhook often provides parsed JSON under raw.body
const body =
  raw.body && typeof raw.body === "object" && !Array.isArray(raw.body)
    ? raw.body
    : null;

// Prefer parsed body when present; otherwise treat raw as already-flat
const req = body ?? raw;

// Get headers (n8n provides these at top level)
const headers = raw.headers || {};

// ============================================================
// AUTH EXTRACTION (Phase 1 Addition)
// ============================================================
const authHeader = headers.authorization || headers.Authorization || '';

let authMethod = 'none';
let bearerToken = null;
let basicCredentials = null;

if (authHeader.startsWith('Bearer ')) {
  authMethod = 'bearer';
  bearerToken = authHeader.slice(7).trim();
} else if (authHeader.startsWith('Basic ')) {
  authMethod = 'basic';
  basicCredentials = authHeader.slice(6).trim();
}

// ============================================================
// NORMALIZE HELPER
// ============================================================
const asObj = (v) =>
  v && typeof v === "object" && !Array.isArray(v) ? v : {};

// Build canonical contract fields
const canonical = {
  gw_action: req.gw_action ?? null,
  gw_workspace_id: req.gw_workspace_id ?? null,
  artifact_type: req.artifact_type ?? null,
  artifact_id: req.artifact_id ?? null,
  selector: asObj(req.selector),

  // IMPORTANT: freeze request intent so it survives later nodes that overwrite $json
  req_artifact_type: req.artifact_type ?? null,
  req_artifact_id: req.artifact_id ?? null,
};

// Auth context (Phase 1)
const authContext = {
  _auth_method: authMethod,
  _bearer_token: bearerToken,
  _basic_credentials: basicCredentials,
  _client_owner_user_id: req.owner_user_id ?? null,
};

// Minimal debug context (non-contract)
canonical._gw_debug = {
  received_shape: body ? "n8n.body" : "flat",
  has_authorization: !!authHeader,
  auth_method_detected: authMethod,
  request_method: raw.method ?? null,
  request_url: raw.url ?? null,
};

// ✅ PASS-THROUGH: keep ALL original request fields, but enforce canonical keys
const out = {
  ...req,
  ...canonical,
  ...authContext,
};

return [{ json: out }];

// NQxb_Gateway_v1__Auth_Resolve_User (Phase 1 - NEW NODE)
// Validate auth and prepare for user resolution.
// - Bearer: mark for Supabase validation
// - Basic: validate credentials, use legacy client-supplied owner_user_id
// - None: reject

const authMethod = $json._auth_method;
const bearerToken = $json._bearer_token;
const basicCredentials = $json._basic_credentials;
const clientOwnerId = $json._client_owner_user_id;

// ============================================================
// AUTH METHOD: BEARER (Chrome Extension path)
// ============================================================
if (authMethod === 'bearer') {
  if (!bearerToken) {
    return [{
      json: {
        ...$json,
        _auth_ok: false,
        _auth_error: {
          code: 'AUTH_INVALID',
          message: 'Bearer token is empty'
        }
      }
    }];
  }

  // Token validation happens in Supabase HTTP node
  // Pass token forward for validation
  return [{
    json: {
      ...$json,
      _auth_ok: 'pending_supabase_validation',
      _auth_method: 'bearer'
    }
  }];
}

// ============================================================
// AUTH METHOD: BASIC (Telegram legacy path)
// ============================================================
if (authMethod === 'basic') {
  // Validate Basic Auth credentials
  const expectedUsername = 'qwrk-gateway';

  try {
    const decoded = Buffer.from(basicCredentials, 'base64').toString('utf8');
    const colonIndex = decoded.indexOf(':');
    const username = colonIndex > 0 ? decoded.slice(0, colonIndex) : decoded;

    // Validate username matches (password check deferred for MVP)
    if (username !== expectedUsername) {
      return [{
        json: {
          ...$json,
          _auth_ok: false,
          _auth_error: {
            code: 'AUTH_INVALID',
            message: 'Invalid Basic Auth credentials'
          }
        }
      }];
    }

    // Legacy path: use client-supplied owner_user_id
    // This is an acknowledged MVP backward-compat violation of the canonical spec
    if (!clientOwnerId) {
      return [{
        json: {
          ...$json,
          _auth_ok: false,
          _auth_error: {
            code: 'AUTH_MISSING_USER',
            message: 'Basic Auth requires owner_user_id in payload (legacy Telegram path)'
          }
        }
      }];
    }

    return [{
      json: {
        ...$json,
        _auth_ok: true,
        _auth_method: 'basic',
        _resolved_user_id: clientOwnerId,
        _auth_source: 'client_supplied_legacy'
      }
    }];

  } catch (e) {
    return [{
      json: {
        ...$json,
        _auth_ok: false,
        _auth_error: {
          code: 'AUTH_INVALID',
          message: 'Malformed Basic Auth header'
        }
      }
    }];
  }
}

// ============================================================
// NO AUTH PROVIDED
// ============================================================
return [{
  json: {
    ...$json,
    _auth_ok: false,
    _auth_error: {
      code: 'AUTH_REQUIRED',
      message: 'Authorization header required (Bearer or Basic)'
    }
  }
}];

// NQxb_Gateway_v1__Process_Supabase_Response (Phase 1 - NEW NODE)
// Extract auth.uid from Supabase response, prepare for user lookup.

const supabaseResponse = $json;
const originalRequest = $('NQxb_Gateway_v1__Auth_Resolve_User').first().json;

// Check if Supabase returned an error or no user
if (supabaseResponse.error || supabaseResponse.statusCode >= 400 || !supabaseResponse.id) {
  return [{
    json: {
      ...originalRequest,
      _auth_ok: false,
      _auth_error: {
        code: 'AUTH_TOKEN_INVALID',
        message: supabaseResponse.error?.message || supabaseResponse.message || 'Token validation failed',
        details: {
          supabase_error: supabaseResponse.error || supabaseResponse.message || 'No user ID returned',
          status_code: supabaseResponse.statusCode || null
        }
      }
    }
  }];
}

// Extract auth.uid (Supabase user ID)
const supabaseAuthId = supabaseResponse.id;
const email = supabaseResponse.email || null;

return [{
  json: {
    ...originalRequest,
    _auth_ok: 'pending_user_lookup',
    _supabase_auth_id: supabaseAuthId,
    _supabase_email: email
  }
}];

// NQxb_Gateway_v1__Finalize_Auth (Phase 1 - NEW NODE)
// Finalize resolved user_id or return auth error.

const userLookup = $json;
const authContext = $('NQxb_Gateway_v1__Process_Supabase_Response').first().json;

// Check if user was found
if (!userLookup || !userLookup.user_id) {
  return [{
    json: {
      ...authContext,
      _auth_ok: false,
      _auth_error: {
        code: 'AUTH_USER_NOT_FOUND',
        message: 'Authenticated Supabase user has no Qwrk account',
        details: {
          supabase_auth_id: authContext._supabase_auth_id
        }
      }
    }
  }];
}

// Success: user resolved from bearer token
return [{
  json: {
    ...authContext,
    _auth_ok: true,
    _auth_method: 'bearer',
    _resolved_user_id: userLookup.user_id,
    _resolved_display_name: userLookup.display_name || null,
    _auth_source: 'supabase_jwt'
  }
}];

// NQxb_Gateway_v1__Gatekeeper_MVP_OwnerOnly (Phase 1 - Updated)
// Combined: envelope validation + allow-lists + MVP Mode owner-only enforcement (workspace lock)
// Phase 1 Update: Uses server-resolved _resolved_user_id instead of client-supplied owner_user_id
//
// Output contract:
// - If blocked: { ok:false, error:{code,message,details}, _gw_route:"error", ... }
// - If allowed: passes through the *entire* canonical request + { ok:true, _gw_route:"ok" }

const OWNER_WORKSPACE_ID = "be0d3a48-c764-44f9-90c8-e846d9dbbd0a";

const ACTION_ALLOWLIST = new Set(["artifact.query", "artifact.list", "artifact.save"]);
const TYPE_ALLOWLIST = new Set(["project", "journal", "restart", "snapshot"]);

function asObj(v) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : {};
}

function fail(code, message, details = {}) {
  return [
    {
      json: {
        ok: false,
        error: { code, message, details },
        _gw_route: "error",
        incoming: $json ?? {},
        _gw_debug: $json?._gw_debug ?? undefined,
        gw_action: $json?.gw_action ?? null,
        gw_workspace_id: $json?.gw_workspace_id ?? null,
        artifact_type: $json?.artifact_type ?? null,
        artifact_id: $json?.artifact_id ?? null,
        selector: asObj($json?.selector),
      },
    },
  ];
}

// ============================================================
// PHASE 1: Verify resolved user identity
// ============================================================
const resolvedUserId = $json?._resolved_user_id;
const authMethod = $json?._auth_method;
const authSource = $json?._auth_source;

if (!resolvedUserId) {
  return fail("AUTH_NO_USER", "User identity could not be resolved", {
    auth_method: authMethod,
    auth_source: authSource
  });
}

// ----- Basic shape checks -----
const gw_action = $json?.gw_action;
const gw_workspace_id = $json?.gw_workspace_id;
const artifact_type = $json?.artifact_type;
const artifact_id = $json?.artifact_id;
const selector = asObj($json?.selector);

// Required: gw_action + workspace_id
if (!gw_action || typeof gw_action !== "string") {
  return fail("VALIDATION_ERROR", "Missing or invalid gw_action", {
    expected: "string",
    got: typeof gw_action,
  });
}
if (!gw_workspace_id || typeof gw_workspace_id !== "string") {
  return fail("VALIDATION_ERROR", "Missing or invalid gw_workspace_id", {
    expected: "uuid string",
    got: typeof gw_workspace_id,
  });
}

// Allow-list: actions
if (!ACTION_ALLOWLIST.has(gw_action)) {
  return fail("ACTION_NOT_ALLOWED", "gw_action not allowed", {
    gw_action,
    allowed: Array.from(ACTION_ALLOWLIST),
  });
}

// MVP owner-only enforcement (workspace lock)
if (gw_workspace_id !== OWNER_WORKSPACE_ID) {
  return fail("WORKSPACE_FORBIDDEN", "Workspace not permitted in MVP owner-only mode", {
    gw_workspace_id,
    allowed_workspace_id: OWNER_WORKSPACE_ID,
  });
}

// Action-specific validation
if (gw_action === "artifact.query") {
  if (!artifact_type || typeof artifact_type !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid artifact_type for artifact.query", {
      expected: "string",
      got: typeof artifact_type,
    });
  }
  if (!TYPE_ALLOWLIST.has(artifact_type)) {
    return fail("ARTIFACT_TYPE_NOT_ALLOWED", "artifact_type not allowed", {
      artifact_type,
      allowed: Array.from(TYPE_ALLOWLIST),
    });
  }
  if (!artifact_id || typeof artifact_id !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid artifact_id for artifact.query", {
      expected: "uuid string",
      got: typeof artifact_id,
    });
  }
}

if (gw_action === "artifact.list") {
  if (!artifact_type || typeof artifact_type !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid artifact_type for artifact.list", {
      expected: "string",
      got: typeof artifact_type,
    });
  }
  if (!TYPE_ALLOWLIST.has(artifact_type)) {
    return fail("ARTIFACT_TYPE_NOT_ALLOWED", "artifact_type not allowed", {
      artifact_type,
      allowed: Array.from(TYPE_ALLOWLIST),
    });
  }
  if (selector.limit !== undefined) {
    const n = Number(selector.limit);
    if (!Number.isFinite(n) || n < 1 || n > 100) {
      return fail("VALIDATION_ERROR", "selector.limit out of range (1-100)", {
        limit: selector.limit,
      });
    }
  }
}

// ============================================================
// PHASE 1: Use server-resolved user identity
// ============================================================
// Override any client-supplied owner_user_id with server-resolved value
// For bearer auth: this enforces server-derived identity
// For basic auth legacy: this passes through the client-supplied value (acknowledged violation)

return [
  {
    json: {
      ...($json ?? {}),
      ok: true,
      _gw_route: "ok",

      // enforce canonical contract fields
      gw_action,
      gw_workspace_id,
      artifact_type: artifact_type ?? null,
      artifact_id: artifact_id ?? null,
      selector,

      // PHASE 1: Server-resolved owner_user_id
      owner_user_id: resolvedUserId,

      // Auth context for downstream logging/debugging
      _auth_method: authMethod,
      _auth_source: authSource,
      _resolved_user_id: resolvedUserId,

      _gw_debug: $json?._gw_debug ?? undefined,
    },
  },
];

// Qxb_Gateway__FlattenWebhookBody
const j = $json ?? {};

// n8n Webhook often provides real payload under `body`
const body =
  (j.body && typeof j.body === 'object' && !Array.isArray(j.body)) ? j.body : null;

// Merge: body fields win over wrapper fields
const merged = body ? { ...j, ...body } : { ...j };

// Optional: remove wrapper to prevent confusion downstream
if (merged.body && merged.body === body) delete merged.body;

return [{ json: merged }];
